SPL_METHOD(SplHeap, top)
{
	zval *value;
	spl_heap_object *intern;
	if (zend_parse_parameters(ZEND_NUM_ARGS() TSRMLS_CC, "") == FAILURE) {
		return;
	}
	intern = (spl_heap_object*)zend_object_store_get_object(getThis() TSRMLS_CC);
	if (intern->heap->flags & SPL_HEAP_CORRUPTED) {
		zend_throw_exception(spl_ce_RuntimeException, "Heap is corrupted, heap properties are no longer ensured.", 0 TSRMLS_CC);
		return;
	}
	value  = (zval *)spl_ptr_heap_top(intern->heap);
	if (!value) {
		zend_throw_exception(spl_ce_RuntimeException, "Can't peek at an empty heap", 0 TSRMLS_CC);
		return;
	}
	RETURN_ZVAL(value, 1, 0);
}

void ChromotingHost::Shutdown(const base::Closure& shutdown_task) {
 if (MessageLoop::current() != context_->main_message_loop()) {
   context_->main_message_loop()->PostTask(
       FROM_HERE,
       base::Bind(&ChromotingHost::Shutdown, this, shutdown_task));
    return;
  }
 {
   base::AutoLock auto_lock(lock_);
   if (state_ == kInitial || state_ == kStopped) {
     state_ = kStopped;
     context_->main_message_loop()->PostTask(FROM_HERE, shutdown_task);
     return;
   }
   if (!shutdown_task.is_null())
     shutdown_tasks_.push_back(shutdown_task);
   if (state_ == kStopping)
     return;
   state_ = kStopping;
  }
  while (!clients_.empty()) {
   scoped_refptr<ClientSession> client = clients_.front();
   client->Disconnect();
   OnClientDisconnected(client);
  }
 ShutdownNetwork();
}

void Range::processNodes(ActionType action, Vector<RefPtr<Node> >& nodes, PassRefPtr<Node> oldContainer, PassRefPtr<Node> newContainer, ExceptionCode& ec)
{
    for (unsigned i = 0; i < nodes.size(); i++) {
        switch (action) {
        case DELETE_CONTENTS:
            oldContainer->removeChild(nodes[i].get(), ec);
            break;
        case EXTRACT_CONTENTS:
            newContainer->appendChild(nodes[i].release(), ec); // will remove n from its parent
            break;
        case CLONE_CONTENTS:
            newContainer->appendChild(nodes[i]->cloneNode(true), ec);
            break;
        }
    }
}

