static void *t_hash_start(struct seq_file *m, loff_t *pos)
{
	struct ftrace_iterator *iter = m->private;
	void *p = NULL;
	loff_t l;
	if (!(iter->flags & FTRACE_ITER_DO_HASH))
		return NULL;
	if (iter->func_pos > *pos)
		return NULL;
	iter->hidx = 0;
	for (l = 0; l <= (*pos - iter->func_pos); ) {
		p = t_hash_next(m, &l);
		if (!p)
			break;
	}
	if (!p)
		return NULL;
	iter->flags |= FTRACE_ITER_HASH;
	return iter;
}

Render_Glyph( int  x_offset,
              int  y_offset )
{
  grBitmap  bit3;
  FT_Pos    x_top, y_top;
  if ( glyph->format != FT_GLYPH_FORMAT_BITMAP )
  {
    error = FT_Render_Glyph( glyph, antialias ? FT_RENDER_MODE_NORMAL
                                              : FT_RENDER_MODE_MONO );
    if ( error )
      return error;
  }
  bit3.rows   = glyph->bitmap.rows;
  bit3.width  = glyph->bitmap.width;
  bit3.pitch  = glyph->bitmap.pitch;
  bit3.buffer = glyph->bitmap.buffer;
  switch ( glyph->bitmap.pixel_mode )
  {
  case FT_PIXEL_MODE_MONO:
    bit3.mode  = gr_pixel_mode_mono;
    bit3.grays = 0;
    break;
  case FT_PIXEL_MODE_GRAY:
    bit3.mode  = gr_pixel_mode_gray;
    bit3.grays = glyph->bitmap.num_grays;
  }
  x_top = x_offset + glyph->bitmap_left;
  y_top = y_offset - glyph->bitmap_top;
  grBlitGlyphToBitmap( &bit, &bit3, x_top, y_top, fore_color );
  return 0;
}

void Browser::OnWindowClosing() {
  if (!ShouldCloseWindow())
    return;
  bool exiting = false;
  bool should_quit_if_last_browser =
      browser_shutdown::IsTryingToQuit() || !BrowserList::WillKeepAlive();
  if (should_quit_if_last_browser && BrowserList::size() == 1) {
    browser_shutdown::OnShutdownStarting(browser_shutdown::WINDOW_CLOSE);
    exiting = true;
  }
  SessionService* session_service = profile()->GetSessionService();
  if (session_service)
    session_service->WindowClosing(session_id());
  TabRestoreService* tab_restore_service = profile()->GetTabRestoreService();
  if (tab_restore_service && type() == TYPE_NORMAL && tab_count())
    tab_restore_service->BrowserClosing(tab_restore_service_delegate());
  NotificationService::current()->Notify(
      NotificationType::BROWSER_CLOSING,
      Source<Browser>(this),
      Details<bool>(&exiting));
  CloseAllTabs();
}

