	vcpu->arch.mmu.get_cr3           = nested_ept_get_cr3;
	vcpu->arch.mmu.inject_page_fault = nested_ept_inject_page_fault;
	vcpu->arch.walk_mmu              = &vcpu->arch.nested_mmu;
	return 0;
}

