bson_iter_init_from_data (bson_iter_t *iter,   /* OUT */
                          const uint8_t *data, /* IN */
                          size_t length)       /* IN */
{
   uint32_t len_le;
   BSON_ASSERT (iter);
   BSON_ASSERT (data);
   if (BSON_UNLIKELY ((length < 5) || (length > INT_MAX))) {
      memset (iter, 0, sizeof *iter);
      return false;
   }
   memcpy (&len_le, data, sizeof (len_le));
   if (BSON_UNLIKELY ((size_t) BSON_UINT32_FROM_LE (len_le) != length)) {
      memset (iter, 0, sizeof *iter);
      return false;
   }
   if (BSON_UNLIKELY (data[length - 1])) {
      memset (iter, 0, sizeof *iter);
      return false;
   }
   iter->raw = (uint8_t *) data;
   iter->len = length;
   iter->off = 0;
   iter->type = 0;
   iter->key = 0;
   iter->d1 = 0;
   iter->d2 = 0;
   iter->d3 = 0;
   iter->d4 = 0;
   iter->next_off = 4;
   iter->err_off = 0;
   return true;
}

void qrio_prstcfg(u8 bit, u8 mode)
{
	u32 prstcfg;
	u8 i;
	void __iomem *qrio_base = (void *)CONFIG_SYS_QRIO_BASE;
 	prstcfg = in_be32(qrio_base + PRSTCFG_OFF);
 	for (i = 0; i < 2; i++) {
		if (mode & (1<<i))
			set_bit(2*bit+i, &prstcfg);
 		else
			clear_bit(2*bit+i, &prstcfg);
 	}
 	out_be32(qrio_base + PRSTCFG_OFF, prstcfg);
}

static void extractAlbumArt(
 const sp<MetaData> &fileMeta, const void *data, size_t size) {
    ALOGV("extractAlbumArt from '%s'", (const char *)data);
    sp<ABuffer> flacBuffer = decodeBase64(AString((const char *)data, size));
 if (flacBuffer == NULL) {
        ALOGE("malformed base64 encoded data.");
 return;
 }
 size_t flacSize = flacBuffer->size();
 uint8_t *flac = flacBuffer->data();
    ALOGV("got flac of size %zu", flacSize);
 uint32_t picType;
 uint32_t typeLen;
 uint32_t descLen;
 uint32_t dataLen;
 char type[128];
 if (flacSize < 8) {
 return;
 }
    picType = U32_AT(flac);
 if (picType != 3) {
 return;
 }
    typeLen = U32_AT(&flac[4]);
 if (typeLen > sizeof(type) - 1) {
 return;
 }
 if (flacSize - 8 < typeLen) {
 return;
 }
    memcpy(type, &flac[8], typeLen);
    type[typeLen] = '\0';
    ALOGV("picType = %d, type = '%s'", picType, type);
 if (!strcmp(type, "-->")) {
 return;
 }
 if (flacSize < 32 || flacSize - 32 < typeLen) {
 return;
 }
    descLen = U32_AT(&flac[8 + typeLen]);
 if (flacSize - 32 - typeLen < descLen) {
 return;
 }
    dataLen = U32_AT(&flac[8 + typeLen + 4 + descLen + 16]);
 if (flacSize - 32 - typeLen - descLen < dataLen) {
 return;
 }
    ALOGV("got image data, %zu trailing bytes",
         flacSize - 32 - typeLen - descLen - dataLen);
    fileMeta->setData(
            kKeyAlbumArt, 0, &flac[8 + typeLen + 4 + descLen + 20], dataLen);
    fileMeta->setCString(kKeyAlbumArtMIME, type);
}

