static void i6300esb_mem_writew(void *vp, hwaddr addr, uint32_t val)
{
    I6300State *d = vp;
    i6300esb_debug("addr = %x, val = %x\n", (int) addr, val);
    if (addr == 0xc && val == 0x80)
        d->unlock_state = 1;
    else if (addr == 0xc && val == 0x86 && d->unlock_state == 1)
        d->unlock_state = 2;
    else {
        if (d->unlock_state == 2) {
            if (addr == 0xc) {
                if ((val & 0x100) != 0)
                    i6300esb_restart_timer(d, 1);
                if ((val & 0x200) != 0 || (val & 0x1000) != 0) {
                    d->previous_reboot_flag = 0;
                }
            }
            d->unlock_state = 0;
        }
    }
}

static int orinoco_ioctl_getsens(struct net_device *dev,
				 struct iw_request_info *info,
				 struct iw_param *srq,
				 char *extra)
{
	struct orinoco_private *priv = ndev_priv(dev);
	hermes_t *hw = &priv->hw;
	u16 val;
	int err;
	unsigned long flags;
	if (!priv->has_sensitivity)
		return -EOPNOTSUPP;
	if (orinoco_lock(priv, &flags) != 0)
		return -EBUSY;
	err = hermes_read_wordrec(hw, USER_BAP,
				  HERMES_RID_CNFSYSTEMSCALE, &val);
	orinoco_unlock(priv, &flags);
	if (err)
		return err;
	srq->value = val;
	srq->fixed = 0; /* auto */
	return 0;
}

xmlCheckLanguageID(const xmlChar * lang)
{
 const xmlChar *cur = lang, *nxt;
 if (cur == NULL)
 return (0);
 if (((cur[0] == 'i') && (cur[1] == '-')) ||
 ((cur[0] == 'I') && (cur[1] == '-')) ||
 ((cur[0] == 'x') && (cur[1] == '-')) ||
 ((cur[0] == 'X') && (cur[1] == '-'))) {
        cur += 2;
 while (((cur[0] >= 'A') && (cur[0] <= 'Z')) ||
 ((cur[0] >= 'a') && (cur[0] <= 'z')))
            cur++;
 return(cur[0] == 0);
 }
    nxt = cur;
 while (((nxt[0] >= 'A') && (nxt[0] <= 'Z')) ||
 ((nxt[0] >= 'a') && (nxt[0] <= 'z')))
           nxt++;
 if (nxt - cur >= 4) {
 if ((nxt - cur > 8) || (nxt[0] != 0))
 return(0);
 return(1);
 }
 if (nxt - cur < 2)
 return(0);
 if (nxt[0] == 0)
 return(1);
 if (nxt[0] != '-')
 return(0);
    nxt++;
    cur = nxt;
 if ((nxt[0] >= '0') && (nxt[0] <= '9'))
 goto region_m49;
 while (((nxt[0] >= 'A') && (nxt[0] <= 'Z')) ||
 ((nxt[0] >= 'a') && (nxt[0] <= 'z')))
           nxt++;
 if (nxt - cur == 4)
 goto script;
 if (nxt - cur == 2)
 goto region;
 if ((nxt - cur >= 5) && (nxt - cur <= 8))
 goto variant;
 if (nxt - cur != 3)
 return(0);
 if (nxt[0] == 0)
 return(1);
 if (nxt[0] != '-')
 return(0);
    nxt++;
    cur = nxt;
 if ((nxt[0] >= '0') && (nxt[0] <= '9'))
 goto region_m49;
 while (((nxt[0] >= 'A') && (nxt[0] <= 'Z')) ||
 ((nxt[0] >= 'a') && (nxt[0] <= 'z')))
           nxt++;
 if (nxt - cur == 2)
 goto region;
 if ((nxt - cur >= 5) && (nxt - cur <= 8))
 goto variant;
 if (nxt - cur != 4)
 return(0);
script:
 if (nxt[0] == 0)
 return(1);
 if (nxt[0] != '-')
 return(0);
    nxt++;
    cur = nxt;
 if ((nxt[0] >= '0') && (nxt[0] <= '9'))
 goto region_m49;
 while (((nxt[0] >= 'A') && (nxt[0] <= 'Z')) ||
 ((nxt[0] >= 'a') && (nxt[0] <= 'z')))
           nxt++;
 if ((nxt - cur >= 5) && (nxt - cur <= 8))
 goto variant;
 if (nxt - cur != 2)
 return(0);
region:
 if (nxt[0] == 0)
 return(1);
 if (nxt[0] != '-')
 return(0);
    nxt++;
    cur = nxt;
 while (((nxt[0] >= 'A') && (nxt[0] <= 'Z')) ||
 ((nxt[0] >= 'a') && (nxt[0] <= 'z')))
           nxt++;
 if ((nxt - cur < 5) || (nxt - cur > 8))
 return(0);
variant:
 if (nxt[0] == 0)
 return(1);
 if (nxt[0] != '-')
 return(0);
 return (1);
region_m49:
 if (((nxt[1] >= '0') && (nxt[1] <= '9')) &&
 ((nxt[2] >= '0') && (nxt[2] <= '9'))) {
        nxt += 3;
 goto region;
 }
 return(0);
}

