 } else {
 SapSocketRequest *recv = (SapSocketRequest*)malloc(sizeof(SapSocketRequest));
 if (!recv) {
            RLOGE("pushRecord: OOM");
            free(reqHeader);
 return;
 }
        recv->token = reqHeader->token;
        recv->curr = reqHeader;
        recv->socketId = id;
        dispatchQueue.enqueue(recv);
 }
