 	CU_add_test(parserTestSuite, "State machine", test_stateMachine);
	for(i=0; suites[i]; i++){
		CU_basic_run_suite(*suites[i]);
		fails_count += CU_get_number_of_tests_failed();
	}
	CU_cleanup_registry();
#ifdef HAVE_LIBXML2
	xmlCleanupParser();
#endif
	return (fails_count == 0 ? 0 : 1);
}

cmsBool ReadOneWChar(cmsIOHANDLER* io,  _cmsDICelem* e, cmsUInt32Number i, wchar_t ** wcstr)
{
    cmsUInt32Number nChars;
      if (e -> Offsets[i] == 0) {
          return TRUE;
      }
      if (!io -> Seek(io, e -> Offsets[i])) return FALSE;
      nChars = e ->Sizes[i] / sizeof(cmsUInt16Number);
      if (*wcstr == NULL) return FALSE;
      if (!_cmsReadWCharArray(io, nChars, *wcstr)) {
          _cmsFree(e ->ContextID, *wcstr);
          return FALSE;
      }
      (*wcstr)[nChars] = 0;
      return TRUE;
}

long long mkvparser::ReadUInt(IMkvReader* pReader, long long pos, long& len) {
  assert(pReader);
  assert(pos >= 0);
  int status;
   len = 1;
   unsigned char b;
  status = pReader->Read(pos, 1, &b);
   if (status < 0)  // error or underflow
     return status;
 if (status > 0) // interpreted as "underflow"
 return E_BUFFER_NOT_FULL;
 if (b == 0) // we can't handle u-int values larger than 8 bytes
 return E_FILE_FORMAT_INVALID;
 unsigned char m = 0x80;
 while (!(b & m)) {
    m >>= 1;
     ++len;
   }
   long long result = b & (~m);
   ++pos;
 for (int i = 1; i < len; ++i) {
    status = pReader->Read(pos, 1, &b);
 if (status < 0) {
      len = 1;
 return status;
 }
 if (status > 0) {
      len = 1;
 return E_BUFFER_NOT_FULL;
 }
    result <<= 8;
    result |= b;
 ++pos;
 }
   return result;
 }

