 LPSTR tr_esc_str(LPCSTR arg, bool format)
 {
 	LPSTR tmp = NULL;
 	size_t cs = 0, x, ds, len;
 	size_t s;
	if (NULL == arg)
		return NULL;
	s = strlen(arg);
	while ((s > 0) && isspace(arg[s - 1]))
		s--;
 	ds = s + 1;
 	if (s)
		tmp = (LPSTR)realloc(tmp, ds * sizeof(CHAR));
 	if (NULL == tmp)
 	{
		fprintf(stderr,  "Could not allocate string buffer.\n");
		exit(-2);
	}
	memset(tmp, 0, ds * sizeof(CHAR));
	for (x = 0; x < s; x++)
	{
		switch (arg[x])
		{
 			case '<':
 				len = format ? 13 : 4;
 				ds += len - 1;
				tmp = (LPSTR)realloc(tmp, ds * sizeof(CHAR));
 				if (NULL == tmp)
 				{
					fprintf(stderr,  "Could not reallocate string buffer.\n");
					exit(-3);
				}
				if (format)
					strncpy(&tmp[cs], "<replaceable>", len);
				else
					strncpy(&tmp[cs], "&lt;", len);
				cs += len;
				break;
 			case '>':
 				len = format ? 14 : 4;
 				ds += len - 1;
				tmp = (LPSTR)realloc(tmp, ds * sizeof(CHAR));
 				if (NULL == tmp)
 				{
					fprintf(stderr,  "Could not reallocate string buffer.\n");
					exit(-4);
				}
				if (format)
					strncpy(&tmp[cs], "</replaceable>", len);
				else
					strncpy(&tmp[cs], "&lt;", len);
				cs += len;
				break;
 			case '\'':
 				ds += 5;
				tmp = (LPSTR)realloc(tmp, ds * sizeof(CHAR));
 				if (NULL == tmp)
 				{
					fprintf(stderr,  "Could not reallocate string buffer.\n");
					exit(-5);
				}
				tmp[cs++] = '&';
				tmp[cs++] = 'a';
				tmp[cs++] = 'p';
				tmp[cs++] = 'o';
				tmp[cs++] = 's';
				tmp[cs++] = ';';
				break;
 			case '"':
 				ds += 5;
				tmp = (LPSTR)realloc(tmp, ds * sizeof(CHAR));
 				if (NULL == tmp)
 				{
					fprintf(stderr,  "Could not reallocate string buffer.\n");
					exit(-6);
				}
				tmp[cs++] = '&';
				tmp[cs++] = 'q';
				tmp[cs++] = 'u';
				tmp[cs++] = 'o';
				tmp[cs++] = 't';
				tmp[cs++] = ';';
				break;
 			case '&':
 				ds += 4;
				tmp = (LPSTR)realloc(tmp, ds * sizeof(CHAR));
 				if (NULL == tmp)
 				{
					fprintf(stderr,  "Could not reallocate string buffer.\n");
					exit(-7);
				}
				tmp[cs++] = '&';
				tmp[cs++] = 'a';
				tmp[cs++] = 'm';
				tmp[cs++] = 'p';
				tmp[cs++] = ';';
				break;
			default:
				tmp[cs++] = arg[x];
				break;
		}
		tmp[ds - 1] = '\0';
	}
	return tmp;
}

v8::Local<v8::Value> V8ValueConverterImpl::ToV8Object(
    v8::Isolate* isolate,
    v8::Local<v8::Object> creation_context,
     const base::DictionaryValue* val) const {
   v8::Local<v8::Object> result(v8::Object::New(isolate));
   for (base::DictionaryValue::Iterator iter(*val);
        !iter.IsAtEnd(); iter.Advance()) {
     const std::string& key = iter.key();
     v8::Local<v8::Value> child_v8 =
         ToV8ValueImpl(isolate, creation_context, &iter.value());
     CHECK(!child_v8.IsEmpty());
    v8::TryCatch try_catch(isolate);
    result->Set(
        v8::String::NewFromUtf8(
            isolate, key.c_str(), v8::String::kNormalString, key.length()),
         child_v8);
    if (try_catch.HasCaught()) {
      LOG(ERROR) << "Setter for property " << key.c_str() << " threw an "
                 << "exception.";
    }
   }
   return result;
}

static int ec_mul_consttime(const EC_GROUP *group, EC_POINT *r,
                            const BIGNUM *scalar, const EC_POINT *point,
                            BN_CTX *ctx)
{
    int i, cardinality_bits, group_top, kbit, pbit, Z_is_one;
    EC_POINT *s = NULL;
    BIGNUM *k = NULL;
    BIGNUM *lambda = NULL;
    BIGNUM *cardinality = NULL;
    BN_CTX *new_ctx = NULL;
    int ret = 0;
    if (ctx == NULL && (ctx = new_ctx = BN_CTX_secure_new()) == NULL)
        return 0;
    BN_CTX_start(ctx);
    s = EC_POINT_new(group);
    if (s == NULL)
        goto err;
    if (point == NULL) {
        if (!EC_POINT_copy(s, group->generator))
            goto err;
    } else {
        if (!EC_POINT_copy(s, point))
            goto err;
    }
    EC_POINT_BN_set_flags(s, BN_FLG_CONSTTIME);
    cardinality = BN_CTX_get(ctx);
    lambda = BN_CTX_get(ctx);
    k = BN_CTX_get(ctx);
    if (k == NULL || !BN_mul(cardinality, group->order, group->cofactor, ctx))
        goto err;
     cardinality_bits = BN_num_bits(cardinality);
     group_top = bn_get_top(cardinality);
    if ((bn_wexpand(k, group_top + 1) == NULL)
        || (bn_wexpand(lambda, group_top + 1) == NULL))
         goto err;
     if (!BN_copy(k, scalar))
        goto err;
    BN_set_flags(k, BN_FLG_CONSTTIME);
    if ((BN_num_bits(k) > cardinality_bits) || (BN_is_negative(k))) {
        if (!BN_nnmod(k, k, cardinality, ctx))
            goto err;
    }
    if (!BN_add(lambda, k, cardinality))
        goto err;
    BN_set_flags(lambda, BN_FLG_CONSTTIME);
    if (!BN_add(k, lambda, cardinality))
        goto err;
     kbit = BN_is_bit_set(lambda, cardinality_bits);
    BN_consttime_swap(kbit, k, lambda, group_top + 1);
     group_top = bn_get_top(group->field);
     if ((bn_wexpand(s->X, group_top) == NULL)
        || (bn_wexpand(s->Y, group_top) == NULL)
        || (bn_wexpand(s->Z, group_top) == NULL)
        || (bn_wexpand(r->X, group_top) == NULL)
        || (bn_wexpand(r->Y, group_top) == NULL)
        || (bn_wexpand(r->Z, group_top) == NULL))
        goto err;
    if (!ec_point_blind_coordinates(group, s, ctx))
        goto err;
    if (!EC_POINT_copy(r, s))
        goto err;
    EC_POINT_BN_set_flags(r, BN_FLG_CONSTTIME);
    if (!EC_POINT_dbl(group, s, s, ctx))
        goto err;
    pbit = 0;
#define EC_POINT_CSWAP(c, a, b, w, t) do {         \
        BN_consttime_swap(c, (a)->X, (b)->X, w);   \
        BN_consttime_swap(c, (a)->Y, (b)->Y, w);   \
        BN_consttime_swap(c, (a)->Z, (b)->Z, w);   \
        t = ((a)->Z_is_one ^ (b)->Z_is_one) & (c); \
        (a)->Z_is_one ^= (t);                      \
        (b)->Z_is_one ^= (t);                      \
} while(0)
    for (i = cardinality_bits - 1; i >= 0; i--) {
        kbit = BN_is_bit_set(k, i) ^ pbit;
        EC_POINT_CSWAP(kbit, r, s, group_top, Z_is_one);
        if (!EC_POINT_add(group, s, r, s, ctx))
            goto err;
        if (!EC_POINT_dbl(group, r, r, ctx))
            goto err;
        pbit ^= kbit;
    }
    EC_POINT_CSWAP(pbit, r, s, group_top, Z_is_one);
#undef EC_POINT_CSWAP
    ret = 1;
 err:
    EC_POINT_free(s);
    BN_CTX_end(ctx);
    BN_CTX_free(new_ctx);
    return ret;
}

static int llc_ui_wait_for_conn(struct sock *sk, long timeout)
{
	DEFINE_WAIT(wait);
	while (1) {
		prepare_to_wait(sk_sleep(sk), &wait, TASK_INTERRUPTIBLE);
		if (sk_wait_event(sk, &timeout, sk->sk_state != TCP_SYN_SENT))
			break;
		if (signal_pending(current) || !timeout)
			break;
	}
	finish_wait(sk_sleep(sk), &wait);
	return timeout;
}

static int read_fragment_table(long long *directory_table_end)
 {
 	int res, i;
	int bytes = SQUASHFS_FRAGMENT_BYTES(sBlk.s.fragments);
	int  indexes = SQUASHFS_FRAGMENT_INDEXES(sBlk.s.fragments);
	long long fragment_table_index[indexes];
 	TRACE("read_fragment_table: %d fragments, reading %d fragment indexes "
 		"from 0x%llx\n", sBlk.s.fragments, indexes,
 		sBlk.s.fragment_table_start);
	if(sBlk.s.fragments == 0) {
		return TRUE;
	}
 	fragment_table = malloc(bytes);
 	if(fragment_table == NULL)
 		EXIT_UNSQUASH("read_fragment_table: failed to allocate "
 			"fragment table\n");
	res = read_fs_bytes(fd, sBlk.s.fragment_table_start,
		SQUASHFS_FRAGMENT_INDEX_BYTES(sBlk.s.fragments),
		fragment_table_index);
 	if(res == FALSE) {
 		ERROR("read_fragment_table: failed to read fragment table "
 			"index\n");
		return FALSE;
	}
	SQUASHFS_INSWAP_FRAGMENT_INDEXES(fragment_table_index, indexes);
	for(i = 0; i < indexes; i++) {
		int expected = (i + 1) != indexes ? SQUASHFS_METADATA_SIZE :
					bytes & (SQUASHFS_METADATA_SIZE - 1);
		int length = read_block(fd, fragment_table_index[i], NULL,
			expected, ((char *) fragment_table) + (i *
			SQUASHFS_METADATA_SIZE));
		TRACE("Read fragment table block %d, from 0x%llx, length %d\n",
			i, fragment_table_index[i], length);
		if(length == FALSE) {
			ERROR("read_fragment_table: failed to read fragment "
				"table index\n");
			return FALSE;
		}
	}
 	for(i = 0; i < sBlk.s.fragments; i++) 
 		SQUASHFS_INSWAP_FRAGMENT_ENTRY(&fragment_table[i]);
 	return TRUE;
 }

