comp_distance_value(MinMax* d1, MinMax* d2, int v1, int v2)
{
  if (v2 <= 0) return -1;
  if (v1 <= 0) return  1;
  v1 *= distance_value(d1);
  v2 *= distance_value(d2);
  if (v2 > v1) return  1;
  if (v2 < v1) return -1;
  if (d2->min < d1->min) return  1;
  if (d2->min > d1->min) return -1;
  return 0;
}

