bool_t xdr_nullstring(XDR *xdrs, char **objp)
{
     u_int size;
     if (xdrs->x_op == XDR_ENCODE) {
	  if (*objp == NULL)
	       size = 0;
	  else
	       size = strlen(*objp) + 1;
     }
     if (! xdr_u_int(xdrs, &size)) {
	  return FALSE;
	}
     switch (xdrs->x_op) {
     case XDR_DECODE:
	  if (size == 0) {
	       return TRUE;
	  } else if (*objp == NULL) {
	       if (*objp == NULL) {
		    errno = ENOMEM;
 		    return FALSE;
 	       }
 	  }
	  return (xdr_opaque(xdrs, *objp, size));
      case XDR_ENCODE:
 	  if (size != 0)
	       return (xdr_opaque(xdrs, *objp, size));
	  return TRUE;
     case XDR_FREE:
	  if (*objp != NULL)
	       mem_free(*objp, size);
	  return TRUE;
     }
     return FALSE;
}

