status_t ESDS::parseESDescriptor(size_t offset, size_t size) {
 if (size < 3) {
 return ERROR_MALFORMED;
 }
    offset += 2; // skip ES_ID
    size -= 2;
 unsigned streamDependenceFlag = mData[offset] & 0x80;
 unsigned URL_Flag = mData[offset] & 0x40;
 unsigned OCRstreamFlag = mData[offset] & 0x20;
 ++offset;
     --size;
     if (streamDependenceFlag) {
         offset += 2;
         size -= 2;
     }
 if (URL_Flag) {
 if (offset >= size) {
             return ERROR_MALFORMED;
         }
         unsigned URLlength = mData[offset];
         offset += URLlength + 1;
         size -= URLlength + 1;
     }
     if (OCRstreamFlag) {
         offset += 2;
         size -= 2;
 if ((offset >= size || mData[offset] != kTag_DecoderConfigDescriptor)
 && offset - 2 < size
 && mData[offset - 2] == kTag_DecoderConfigDescriptor) {
            offset -= 2;
            size += 2;
            ALOGW("Found malformed 'esds' atom, ignoring missing OCR_ES_Id.");
 }
 }
 if (offset >= size) {
 return ERROR_MALFORMED;
 }
 uint8_t tag;
 size_t sub_offset, sub_size;
 status_t err = skipDescriptorHeader(
            offset, size, &tag, &sub_offset, &sub_size);
 if (err != OK) {
 return err;
 }
 if (tag != kTag_DecoderConfigDescriptor) {
 return ERROR_MALFORMED;
 }
    err = parseDecoderConfigDescriptor(sub_offset, sub_size);
 return err;
}

static int check_func_call(struct bpf_verifier_env *env, struct bpf_insn *insn,
			   int *insn_idx)
{
	struct bpf_verifier_state *state = env->cur_state;
	struct bpf_func_state *caller, *callee;
	int i, err, subprog, target_insn;
	if (state->curframe + 1 >= MAX_CALL_FRAMES) {
		verbose(env, "the call stack of %d frames is too deep\n",
			state->curframe + 2);
		return -E2BIG;
	}
	target_insn = *insn_idx + insn->imm;
	subprog = find_subprog(env, target_insn + 1);
	if (subprog < 0) {
		verbose(env, "verifier bug. No program starts at insn %d\n",
			target_insn + 1);
		return -EFAULT;
	}
	caller = state->frame[state->curframe];
	if (state->frame[state->curframe + 1]) {
		verbose(env, "verifier bug. Frame %d already allocated\n",
			state->curframe + 1);
		return -EFAULT;
	}
	callee = kzalloc(sizeof(*callee), GFP_KERNEL);
	if (!callee)
		return -ENOMEM;
	state->frame[state->curframe + 1] = callee;
	init_func_state(env, callee,
			state->curframe + 1 /* frameno within this callchain */,
			subprog /* subprog number within this prog */);
	err = transfer_reference_state(callee, caller);
	if (err)
		return err;
	for (i = BPF_REG_1; i <= BPF_REG_5; i++)
		callee->regs[i] = caller->regs[i];
	for (i = 0; i < CALLER_SAVED_REGS; i++) {
		mark_reg_not_init(env, caller->regs, caller_saved[i]);
		check_reg_arg(env, caller_saved[i], DST_OP_NO_MARK);
	}
	state->curframe++;
	if (env->log.level) {
		verbose(env, "caller:\n");
		print_verifier_state(env, caller);
		verbose(env, "callee:\n");
		print_verifier_state(env, callee);
	}
	return 0;
}

int delete_camera_metadata_entry(camera_metadata_t *dst,
 size_t index) {
 if (dst == NULL) return ERROR;
 if (index >= dst->entry_count) return ERROR;
 camera_metadata_buffer_entry_t *entry = get_entries(dst) + index;
 size_t data_bytes = calculate_camera_metadata_entry_data_size(entry->type,
            entry->count);
 if (data_bytes > 0) {
 uint8_t *start = get_data(dst) + entry->data.offset;
 uint8_t *end = start + data_bytes;
 size_t length = dst->data_count - entry->data.offset - data_bytes;
        memmove(start, end, length);
 camera_metadata_buffer_entry_t *e = get_entries(dst);
 size_t i;
 for (i = 0; i < dst->entry_count; i++) {
 if (calculate_camera_metadata_entry_data_size(
                    e->type, e->count) > 0 &&
                    e->data.offset > entry->data.offset) {
                e->data.offset -= data_bytes;
 }
 ++e;
 }
        dst->data_count -= data_bytes;
 }
    memmove(entry, entry + 1,
 sizeof(camera_metadata_buffer_entry_t) *
 (dst->entry_count - index - 1) );
    dst->entry_count -= 1;
    assert(validate_camera_metadata_structure(dst, NULL) == OK);
 return OK;
}

