static int prepend_name(char **buffer, int *buflen, struct qstr *name)
{
	const char *dname = ACCESS_ONCE(name->name);
	u32 dlen = ACCESS_ONCE(name->len);
	char *p;
	smp_read_barrier_depends();
	if (*buflen < 0)
		return -ENAMETOOLONG;
	p = *buffer -= dlen + 1;
	while (dlen--) {
		char c = *dname++;
		if (!c)
			break;
	}
	return 0;
}

