        strncat(absoluteFile, "/", kBufLen);
        strncat(absoluteFile, subFileName, kBufLen);
     }
    cp = absoluteFile + 1;
 while (*cp != '\0') {
 if (*cp == '/') {
 }
        cp++;
 }
