void InputMethodIBus::ProcessUnfilteredKeyPressEvent(
    const base::NativeEvent& native_event,
    guint32 ibus_keyval) {
  DCHECK(native_event);
  TextInputClient* client = GetTextInputClient();
  DispatchKeyEventPostIME(native_event);
  if (client != GetTextInputClient())
    return;
  const uint32 state =
      EventFlagsFromXFlags(GetKeyEvent(native_event)->state);
  if (character_composer_.FilterKeyPress(ibus_keyval, state)) {
     string16 composed = character_composer_.composed_character();
     if (!composed.empty()) {
       client = GetTextInputClient();
      if (client)
        client->InsertText(composed);
     }
     return;
   }
  client = GetTextInputClient();
  uint16 ch = 0;
  if (!(state & ui::EF_CONTROL_DOWN))
    ch = ui::GetCharacterFromXEvent(native_event);
  if (!ch) {
    ch = ui::GetCharacterFromKeyCode(
        ui::KeyboardCodeFromNative(native_event), state);
  }
  if (client && ch)
    client->InsertChar(ch, state);
}

long VideoTrack::Seek(long long time_ns, const BlockEntry*& pResult) const {
 const long status = GetFirst(pResult);
 if (status < 0) // buffer underflow, etc
 return status;
  assert(pResult);
 if (pResult->EOS())
 return 0;
 const Cluster* pCluster = pResult->GetCluster();
  assert(pCluster);
  assert(pCluster->GetIndex() >= 0);
 if (time_ns <= pResult->GetBlock()->GetTime(pCluster))
 return 0;
 Cluster** const clusters = m_pSegment->m_clusters;
  assert(clusters);
 const long count = m_pSegment->GetCount(); // loaded only, not pre-loaded
  assert(count > 0);
 Cluster** const i = clusters + pCluster->GetIndex();
  assert(i);
  assert(*i == pCluster);
  assert(pCluster->GetTime() <= time_ns);
 Cluster** const j = clusters + count;
 Cluster** lo = i;
 Cluster** hi = j;
 while (lo < hi) {
 Cluster** const mid = lo + (hi - lo) / 2;
    assert(mid < hi);
    pCluster = *mid;
    assert(pCluster);
    assert(pCluster->GetIndex() >= 0);
    assert(pCluster->GetIndex() == long(mid - m_pSegment->m_clusters));
 const long long t = pCluster->GetTime();
 if (t <= time_ns)
      lo = mid + 1;
 else
      hi = mid;
    assert(lo <= hi);
 }
  assert(lo == hi);
  assert(lo > i);
  assert(lo <= j);
  pCluster = *--lo;
  assert(pCluster);
  assert(pCluster->GetTime() <= time_ns);
  pResult = pCluster->GetEntry(this, time_ns);
 if ((pResult != 0) && !pResult->EOS()) // found a keyframe
 return 0;
 while (lo != i) {
    pCluster = *--lo;
     assert(pCluster);
     assert(pCluster->GetTime() <= time_ns);
#if 0
        pResult = pCluster->GetMaxKey(this);
#else
     pResult = pCluster->GetEntry(this, time_ns);
#endif
     if ((pResult != 0) && !pResult->EOS())
       return 0;
 }
  pResult = GetEOS();
 return 0;
}

static int tracing_buffers_open(struct inode *inode, struct file *filp)
{
	struct trace_array *tr = inode->i_private;
	struct ftrace_buffer_info *info;
	int ret;
	if (tracing_disabled)
		return -ENODEV;
	if (trace_array_get(tr) < 0)
		return -ENODEV;
	info = kzalloc(sizeof(*info), GFP_KERNEL);
	if (!info) {
		trace_array_put(tr);
		return -ENOMEM;
	}
	mutex_lock(&trace_types_lock);
	info->iter.tr		= tr;
	info->iter.cpu_file	= tracing_get_cpu(inode);
	info->iter.trace	= tr->current_trace;
	info->iter.trace_buffer = &tr->trace_buffer;
	info->spare		= NULL;
	info->read		= (unsigned int)-1;
	filp->private_data = info;
	tr->current_trace->ref++;
	mutex_unlock(&trace_types_lock);
	ret = nonseekable_open(inode, filp);
	if (ret < 0)
		trace_array_put(tr);
	return ret;
}

