parse_escapes(char *src, struct mtree_entry *mentry)
{
	char *dest = src;
	char c;
	if (mentry != NULL && strcmp(src, ".") == 0)
		mentry->full = 1;
	while (*src != '\0') {
		c = *src++;
		if (c == '/' && mentry != NULL)
			mentry->full = 1;
		if (c == '\\') {
			switch (src[0]) {
			case '0':
				if (src[1] < '0' || src[1] > '7') {
					c = 0;
					++src;
					break;
				}
			case '1':
			case '2':
			case '3':
				if (src[1] >= '0' && src[1] <= '7' &&
				    src[2] >= '0' && src[2] <= '7') {
					c = (src[0] - '0') << 6;
					c |= (src[1] - '0') << 3;
					c |= (src[2] - '0');
					src += 3;
				}
				break;
			case 'a':
				c = '\a';
				++src;
				break;
			case 'b':
				c = '\b';
				++src;
				break;
			case 'f':
				c = '\f';
				++src;
				break;
			case 'n':
				c = '\n';
				++src;
				break;
			case 'r':
				c = '\r';
				++src;
				break;
			case 's':
				c = ' ';
				++src;
				break;
			case 't':
				c = '\t';
				++src;
				break;
			case 'v':
				c = '\v';
				++src;
				break;
			case '\\':
				c = '\\';
				++src;
				break;
			}
		}
	}
}

void flush_tlb_kernel_range(unsigned long start, unsigned long end)
{
	if (end == TLB_FLUSH_ALL ||
	    (end - start) > tlb_single_page_flush_ceiling * PAGE_SIZE) {
		on_each_cpu(do_flush_tlb_all, NULL, 1);
	} else {
		struct flush_tlb_info info;
		info.flush_start = start;
		info.flush_end = end;
		on_each_cpu(do_kernel_range_flush, &info, 1);
	}
}

bool GetUrlFromHDrop(IDataObject* data_object,
                    base::string16* url,
                     base::string16* title) {
  DCHECK(data_object && url && title);
  STGMEDIUM medium;
  if (!GetData(data_object, Clipboard::GetCFHDropFormatType(), &medium))
    return false;
 HDROP hdrop = static_cast<HDROP>(GlobalLock(medium.hGlobal));
 if (!hdrop)
   return false;
 bool success = false;
 wchar_t filename[MAX_PATH];
 if (DragQueryFileW(hdrop, 0, filename, arraysize(filename))) {
   wchar_t url_buffer[INTERNET_MAX_URL_LENGTH];
   if (0 == _wcsicmp(PathFindExtensionW(filename), L".url") &&
       GetPrivateProfileStringW(L"InternetShortcut", L"url", 0, url_buffer,
                                arraysize(url_buffer), filename)) {
     url->assign(url_buffer);
     PathRemoveExtension(filename);
     title->assign(PathFindFileName(filename));
     success = true;
    }
  }
 DragFinish(hdrop);
 GlobalUnlock(medium.hGlobal);
  return success;
}

