 if (id < 0) //error (or underflow)
 return static_cast<long>(id);
        if ((id == 0x0F43B675) || (id == 0x0C53BB6B)) //Cluster ID or Cues ID
        {
             element_size = pos - element_start;
             assert(element_size > 0);
